            resultado.Value.where.Should().Be($"[{DBFornecedoresDicInfo.PTabelaNome}].{DBFornecedoresDicInfo.CampoCodigo} BETWEEN @{DBFornecedoresDicInfo.CampoCodigo} AND @{DBFornecedoresDicInfo.CampoCodigo}_end");
            resultado.Value.parametros.Should().HaveCount(2);
        }

